import { useEffect, useRef, useState, useCallback } from 'react';
import { mat4 } from 'gl-matrix';
import { WebGLRenderer } from './engine/renderer';
import { WtClient } from './engine/wt-client';
import { GameState } from './game/state';
import { Snapshot, EntityType } from './types';

const SERVER_URL = 'https://localhost:4433';

type ConnectionState = 'disconnected' | 'connecting' | 'connected' | 'error';

export default function App() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const rendererRef = useRef<WebGLRenderer | null>(null);
  const gameStateRef = useRef(new GameState());
  const clientRef = useRef<WtClient | null>(null);
  const [connectionState, setConnectionState] = useState<ConnectionState>('disconnected');
  const [entityCount, setEntityCount] = useState(0);
  const [playerBaseHealth, setPlayerBaseHealth] = useState({ current: 0, max: 0 });
  const [enemyBaseHealth, setEnemyBaseHealth] = useState({ current: 0, max: 0 });
  const [tick, setTick] = useState(0);
  const animFrameRef = useRef<number>(0);
  const lastSnapshotTimeRef = useRef(0);
  const snapshotIntervalRef = useRef(33);

  const handleSnapshot = useCallback((snapshot: Snapshot) => {
    gameStateRef.current.applySnapshot(snapshot);
    setEntityCount(snapshot.entities.length);
    setTick(snapshot.tick);

    const pb = gameStateRef.current.getBaseHealth(0);
    if (pb) setPlayerBaseHealth(pb);

    const eb = gameStateRef.current.getBaseHealth(1);
    if (eb) setEnemyBaseHealth(eb);

    lastSnapshotTimeRef.current = performance.now();
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    rendererRef.current = new WebGLRenderer(canvas);

    const client = new WtClient(SERVER_URL);
    client.setOnSnapshot(handleSnapshot);
    clientRef.current = client;

    let lastTime = performance.now();

    const loop = (time: number) => {
      const dt = (time - lastTime) / 1000;
      lastTime = time;

      const elapsedSinceSnapshot = time - lastSnapshotTimeRef.current;
      const factor = Math.min(elapsedSinceSnapshot / snapshotIntervalRef.current, 1.0);
      gameStateRef.current.interpolate(factor);

      const zoom = 2.0;
      const viewportWidth = canvas.width * zoom;
      const viewportHeight = canvas.height * zoom;
      const aspect = canvas.width / canvas.height;

      const projectionMatrix = mat4.create();
      mat4.perspective(projectionMatrix, Math.PI / 4, aspect, 10, 10000);

      const viewMatrix = mat4.create();
      const cameraZ = Math.max(viewportWidth, viewportHeight);
      mat4.lookAt(viewMatrix, [0, 0, cameraZ], [0, 0, 0], [0, 1, 0]);

      const { positions, colors, sizes, types, count } = gameStateRef.current.getInterpolatedPositions();

      rendererRef.current?.render(
        positions,
        colors,
        sizes,
        types,
        count,
        viewMatrix,
        projectionMatrix,
        time / 1000,
      );

      animFrameRef.current = requestAnimationFrame(loop);
    };

    animFrameRef.current = requestAnimationFrame(loop);

    const handleResize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', handleResize);

    return () => {
      cancelAnimationFrame(animFrameRef.current);
      window.removeEventListener('resize', handleResize);
      client.disconnect();
    };
  }, [handleSnapshot]);

  const connect = async () => {
    setConnectionState('connecting');
    try {
      await clientRef.current?.connect();
      setConnectionState('connected');
    } catch {
      setConnectionState('error');
    }
  };

  return (
    <div className="relative w-full h-screen bg-slate-950 overflow-hidden font-sans text-white">
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full" />

      {connectionState === 'disconnected' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-950/80 backdrop-blur-sm">
          <h1 className="text-8xl font-black italic tracking-tighter uppercase mb-2 text-transparent bg-clip-text bg-gradient-to-b from-white to-white/20">
            STRIKE 2.5D
          </h1>
          <p className="text-white/40 uppercase tracking-[0.5em] text-sm mb-12">AI Arena Spectator</p>
          <button
            onClick={connect}
            className="group relative flex items-center gap-4 bg-white text-black px-12 py-5 rounded-full font-bold text-xl hover:scale-105 transition-all active:scale-95"
          >
            CONNECT TO SERVER
            <div className="absolute -inset-1 bg-white/20 rounded-full blur opacity-0 group-hover:opacity-100 transition-opacity" />
          </button>
        </div>
      )}

      {connectionState === 'connecting' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-950/80 backdrop-blur-sm">
          <h1 className="text-6xl font-black italic tracking-tighter uppercase mb-4 text-white/60">
            CONNECTING...
          </h1>
          <p className="text-white/30 uppercase tracking-widest text-sm">Establishing WebTransport link</p>
        </div>
      )}

      {connectionState === 'error' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-red-950/80 backdrop-blur-sm">
          <h1 className="text-6xl font-black italic tracking-tighter uppercase mb-4 text-red-400">
            CONNECTION FAILED
          </h1>
          <p className="text-red-300/60 mb-8">Is the server running on port 4433?</p>
          <button
            onClick={connect}
            className="flex items-center gap-4 bg-white text-black px-12 py-5 rounded-full font-bold text-xl hover:scale-105 transition-all active:scale-95"
          >
            RETRY
          </button>
        </div>
      )}

      {connectionState === 'connected' && (
        <>
          <div className="absolute top-6 left-6 flex flex-col gap-4 pointer-events-none">
            <div className="flex items-center gap-3 bg-black/40 backdrop-blur-md p-3 rounded-2xl border border-white/10">
              <div className="w-3 h-3 rounded-full bg-emerald-400 animate-pulse" />
              <span className="font-mono font-bold text-sm text-emerald-400">LIVE</span>
            </div>

            <div className="flex items-center gap-3 bg-black/40 backdrop-blur-md p-3 rounded-2xl border border-white/10">
              <div className="w-48 h-3 bg-white/10 rounded-full overflow-hidden">
                <div
                  className="h-full bg-blue-400 transition-all duration-300"
                  style={{ width: `${playerBaseHealth.max > 0 ? (playerBaseHealth.current / playerBaseHealth.max) * 100 : 0}%` }}
                />
              </div>
              <span className="font-mono font-bold text-lg">{Math.ceil(playerBaseHealth.current)}</span>
            </div>
          </div>

          <div className="absolute top-6 right-6 flex flex-col items-end gap-4 pointer-events-none">
            <div className="flex items-center gap-3 bg-black/40 backdrop-blur-md p-3 rounded-2xl border border-white/10">
              <span className="font-mono font-bold text-2xl tracking-tighter">TICK: {tick}</span>
            </div>

            <div className="flex items-center gap-3 bg-black/40 backdrop-blur-md p-3 rounded-2xl border border-white/10">
              <span className="font-mono font-bold text-2xl tracking-tighter">ENTITIES: {entityCount}</span>
            </div>

            <div className="flex items-center gap-3 bg-black/40 backdrop-blur-md p-3 rounded-2xl border border-white/10">
              <span className="font-mono font-bold text-lg">{Math.ceil(enemyBaseHealth.current)}</span>
              <div className="w-48 h-3 bg-white/10 rounded-full overflow-hidden flex justify-end">
                <div
                  className="h-full bg-red-600 transition-all duration-300"
                  style={{ width: `${enemyBaseHealth.max > 0 ? (enemyBaseHealth.current / enemyBaseHealth.max) * 100 : 0}%` }}
                />
              </div>
            </div>
          </div>

          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 pointer-events-none">
            <div className="flex items-center gap-6 bg-black/40 backdrop-blur-md px-6 py-3 rounded-2xl border border-white/10">
              <span className="text-white/40 text-xs font-bold uppercase tracking-widest">
                <span className="text-blue-400">●</span> Player Base
              </span>
              <span className="text-white/20">|</span>
              <span className="text-white/40 text-xs font-bold uppercase tracking-widest">
                <span className="text-red-500">●</span> Enemy Base
              </span>
              <span className="text-white/20">|</span>
              <span className="text-white/40 text-xs font-bold uppercase tracking-widest">
                <span className="text-yellow-400">●</span> Bullets
              </span>
            </div>
          </div>
        </>
      )}
    </div>
  );
}

const VERT = `#version 300 es
in vec3 a_position;
in vec4 a_color;
in float a_size;
in float a_type;

uniform mat4 u_projection;
uniform mat4 u_view;
uniform float u_time;

out vec4 v_color;
out float v_type;
out vec3 v_position;

void main() {
    v_color = a_color;
    v_type = a_type;
    v_position = a_position;

    vec4 clipPos = u_projection * u_view * vec4(a_position, 1.0);
    gl_Position = clipPos;
    gl_PointSize = a_size * (300.0 / clipPos.w);
}`;

const FRAG = `#version 300 es
precision mediump float;

in vec4 v_color;
in float v_type;
in vec3 v_position;

out vec4 fragColor;

void main() {
    vec2 coord = gl_PointCoord * 2.0 - 1.0;
    float dist = length(coord);

    if (dist > 1.0) discard;

    vec3 color = v_color.rgb;
    float alpha = v_color.a;

    if (v_type < 0.5) {
        float glow = 1.0 - dist;
        color += vec3(0.1) * glow;
    } else if (v_type < 1.5) {
        float core = smoothstep(0.5, 0.0, dist);
        color += vec3(0.5, 0.5, 0.0) * core;
    } else if (v_type < 2.5) {
        float ring = smoothstep(0.8, 0.6, dist) - smoothstep(0.6, 0.4, dist);
        color += vec3(0.2) * ring;
        float inner = smoothstep(0.4, 0.0, dist);
        color = mix(color, vec3(0.1, 0.3, 0.5), inner);
    }

    float edge = 1.0 - smoothstep(0.7, 1.0, dist);
    alpha *= edge;

    fragColor = vec4(color, alpha);
}`;

const GRID_VERT = `#version 300 es
in vec3 a_position;
in vec4 a_color;

uniform mat4 u_projection;
uniform mat4 u_view;

out vec4 v_color;

void main() {
    v_color = a_color;
    gl_Position = u_projection * u_view * vec4(a_position, 1.0);
}`;

const GRID_FRAG = `#version 300 es
precision mediump float;

in vec4 v_color;
out vec4 fragColor;

void main() {
    fragColor = v_color;
}`;

import type { mat4 } from 'gl-matrix';

export class WebGLRenderer {
  private gl: WebGL2RenderingContext;
  private program: WebGLProgram;
  private gridProgram: WebGLProgram;
  private vao: WebGLVertexArrayObject;
  private gridVao: WebGLVertexArrayObject;
  private posBuffer: WebGLBuffer;
  private colorBuffer: WebGLBuffer;
  private sizeBuffer: WebGLBuffer;
  private typeBuffer: WebGLBuffer;
  private gridPosBuffer: WebGLBuffer;
  private gridColorBuffer: WebGLBuffer;
  private gridPositions!: Float32Array;
  private gridColors!: Float32Array;
  private gridVertexCount = 0;

  private uProjection: WebGLUniformLocation;
  private uView: WebGLUniformLocation;
  private uTime: WebGLUniformLocation;
  private uGridProjection: WebGLUniformLocation;
  private uGridView: WebGLUniformLocation;

  private maxEntities = 100000;
  private positions: Float32Array;
  private colors: Float32Array;
  private sizes: Float32Array;
  private types: Float32Array;

  constructor(canvas: HTMLCanvasElement) {
    const gl = canvas.getContext('webgl2', { antialias: true, alpha: false });
    if (!gl) throw new Error('WebGL2 not supported');
    this.gl = gl;

    this.program = this.createProgram(VERT, FRAG);
    this.gridProgram = this.createProgram(GRID_VERT, GRID_FRAG);

    this.uProjection = gl.getUniformLocation(this.program, 'u_projection')!;
    this.uView = gl.getUniformLocation(this.program, 'u_view')!;
    this.uTime = gl.getUniformLocation(this.program, 'u_time')!;
    this.uGridProjection = gl.getUniformLocation(this.gridProgram, 'u_projection')!;
    this.uGridView = gl.getUniformLocation(this.gridProgram, 'u_view')!;

    this.positions = new Float32Array(this.maxEntities * 3);
    this.colors = new Float32Array(this.maxEntities * 4);
    this.sizes = new Float32Array(this.maxEntities);
    this.types = new Float32Array(this.maxEntities);

    this.vao = gl.createVertexArray()!;
    gl.bindVertexArray(this.vao);

    this.posBuffer = gl.createBuffer()!;
    gl.bindBuffer(gl.ARRAY_BUFFER, this.posBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, this.positions.byteLength, gl.DYNAMIC_DRAW);
    gl.enableVertexAttribArray(0);
    gl.vertexAttribPointer(0, 3, gl.FLOAT, false, 0, 0);

    this.colorBuffer = gl.createBuffer()!;
    gl.bindBuffer(gl.ARRAY_BUFFER, this.colorBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, this.colors.byteLength, gl.DYNAMIC_DRAW);
    gl.enableVertexAttribArray(1);
    gl.vertexAttribPointer(1, 4, gl.FLOAT, false, 0, 0);

    this.sizeBuffer = gl.createBuffer()!;
    gl.bindBuffer(gl.ARRAY_BUFFER, this.sizeBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, this.sizes.byteLength, gl.DYNAMIC_DRAW);
    gl.enableVertexAttribArray(2);
    gl.vertexAttribPointer(2, 1, gl.FLOAT, false, 0, 0);

    this.typeBuffer = gl.createBuffer()!;
    gl.bindBuffer(gl.ARRAY_BUFFER, this.typeBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, this.types.byteLength, gl.DYNAMIC_DRAW);
    gl.enableVertexAttribArray(3);
    gl.vertexAttribPointer(3, 1, gl.FLOAT, false, 0, 0);

    this.gridVao = gl.createVertexArray()!;
    gl.bindVertexArray(this.gridVao);

    this.gridPosBuffer = gl.createBuffer()!;
    this.gridColorBuffer = gl.createBuffer()!;

    this.buildGrid();

    gl.bindVertexArray(null);
    gl.enable(gl.BLEND);
    gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
    gl.enable(gl.DEPTH_TEST);
    gl.depthFunc(gl.LEQUAL);
  }

  private buildGrid() {
    const gridSize = 40;
    const spacing = 150;
    const count = (gridSize * 2 + 1) ** 2;
    this.gridPositions = new Float32Array(count * 3);
    this.gridColors = new Float32Array(count * 4);
    this.gridVertexCount = count;

    let idx = 0;
    for (let x = -gridSize; x <= gridSize; x++) {
      for (let y = -gridSize; y <= gridSize; y++) {
        this.gridPositions[idx * 3] = x * spacing;
        this.gridPositions[idx * 3 + 1] = y * spacing;
        this.gridPositions[idx * 3 + 2] = 0;
        this.gridColors[idx * 4] = 0.15;
        this.gridColors[idx * 4 + 1] = 0.15;
        this.gridColors[idx * 4 + 2] = 0.15;
        this.gridColors[idx * 4 + 3] = 1.0;
        idx++;
      }
    }

    const gl = this.gl;
    gl.bindVertexArray(this.gridVao);

    gl.bindBuffer(gl.ARRAY_BUFFER, this.gridPosBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, this.gridPositions, gl.STATIC_DRAW);
    gl.enableVertexAttribArray(0);
    gl.vertexAttribPointer(0, 3, gl.FLOAT, false, 0, 0);

    gl.bindBuffer(gl.ARRAY_BUFFER, this.gridColorBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, this.gridColors, gl.STATIC_DRAW);
    gl.enableVertexAttribArray(1);
    gl.vertexAttribPointer(1, 4, gl.FLOAT, false, 0, 0);

    gl.bindVertexArray(null);
  }

  private createProgram(vs: string, fs: string): WebGLProgram {
    const gl = this.gl;
    const vShader = this.compileShader(gl.VERTEX_SHADER, vs);
    const fShader = this.compileShader(gl.FRAGMENT_SHADER, fs);
    const program = gl.createProgram()!;
    gl.attachShader(program, vShader);
    gl.attachShader(program, fShader);
    gl.linkProgram(program);
    if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
      throw new Error(gl.getProgramInfoLog(program) ?? 'Program link failed');
    }
    return program;
  }

  private compileShader(type: number, src: string): WebGLShader {
    const gl = this.gl;
    const shader = gl.createShader(type)!;
    gl.shaderSource(shader, src);
    gl.compileShader(shader);
    if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
      throw new Error(gl.getShaderInfoLog(shader) ?? 'Shader compile failed');
    }
    return shader;
  }

  render(
    positions: Float32Array,
    colors: Float32Array,
    sizes: Float32Array,
    types: Float32Array,
    count: number,
    viewMatrix: mat4,
    projectionMatrix: mat4,
    time: number,
  ) {
    const gl = this.gl;
    gl.viewport(0, 0, gl.canvas.width, gl.canvas.height);
    gl.clearColor(0.008, 0.016, 0.047, 1.0);
    gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);

    gl.useProgram(this.gridProgram);
    gl.uniformMatrix4fv(this.uGridProjection, false, new Float32Array(projectionMatrix));
    gl.uniformMatrix4fv(this.uGridView, false, new Float32Array(viewMatrix));
    gl.bindVertexArray(this.gridVao);
    gl.drawArrays(gl.POINTS, 0, this.gridVertexCount);

    if (count > 0) {
      gl.useProgram(this.program);
      gl.uniformMatrix4fv(this.uProjection, false, new Float32Array(projectionMatrix));
      gl.uniformMatrix4fv(this.uView, false, new Float32Array(viewMatrix));
      gl.uniform1f(this.uTime, time);

      gl.bindVertexArray(this.vao);

      gl.bindBuffer(gl.ARRAY_BUFFER, this.posBuffer);
      gl.bufferSubData(gl.ARRAY_BUFFER, 0, positions.subarray(0, count * 3));

      gl.bindBuffer(gl.ARRAY_BUFFER, this.colorBuffer);
      gl.bufferSubData(gl.ARRAY_BUFFER, 0, colors.subarray(0, count * 4));

      gl.bindBuffer(gl.ARRAY_BUFFER, this.sizeBuffer);
      gl.bufferSubData(gl.ARRAY_BUFFER, 0, sizes.subarray(0, count));

      gl.bindBuffer(gl.ARRAY_BUFFER, this.typeBuffer);
      gl.bufferSubData(gl.ARRAY_BUFFER, 0, types.subarray(0, count));

      gl.drawArrays(gl.POINTS, 0, count);
    }
  }
}

