use std::sync::Arc;
use tokio::sync::RwLock;
use tracing::{info, warn};
use wtransport::endpoint::Endpoint;
use wtransport::ServerConfig;
use wtransport::Identity;
use wtransport::tls::Certificate;
use wtransport::tls::CertificateChain;
use wtransport::tls::PrivateKey;
use crate::network::protocol::{Snapshot, EntityType};

#[derive(Clone)]
pub struct ClientSession {
    pub id: usize,
}

pub struct WtServer {
    clients: Arc<RwLock<Vec<ClientSession>>>,
    snapshot_tx: tokio::sync::watch::Sender<Option<Snapshot>>,
    cert_hash: Arc<Vec<u8>>,
}

impl WtServer {
    pub fn new() -> (Self, tokio::sync::watch::Receiver<Option<Snapshot>>) {
        let (snapshot_tx, snapshot_rx) = tokio::sync::watch::channel(None);
        let (cert_der, key_der) = generate_self_signed_cert().expect("Failed to generate cert");
        let cert_hash = ring_sha256(&cert_der);

        info!("Certificate SHA-256 hash (base64): {}", base64_encode(&cert_hash));

        let identity = Identity::new(
            CertificateChain::single(Certificate::from_der(cert_der).unwrap()),
            PrivateKey::from_der_pkcs8(key_der),
        );

        (
            Self {
                clients: Arc::new(RwLock::new(Vec::new())),
                snapshot_tx,
                cert_hash: Arc::new(cert_hash),
            },
            snapshot_rx,
        )
    }

    pub fn cert_hash(&self) -> &[u8] {
        &self.cert_hash
    }

    pub async fn start(&self, port: u16) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
        let cert_hash = self.cert_hash.clone();

        // Serve cert hash on HTTP so the client can fetch it
        let hash_clone = cert_hash.clone();
        tokio::spawn(async move {
            use tokio::net::TcpListener;
            use tokio::io::AsyncWriteExt;

            let listener = TcpListener::bind("0.0.0.0:4434").await.unwrap();
            info!("Cert hash HTTP server on http://localhost:4434/cert-hash");

            loop {
                if let Ok((mut stream, _)) = listener.accept().await {
                    let hash_b64 = base64_encode(&hash_clone);
                    let body = format!("{{\"hash\":\"{}\"}}", hash_b64);
                    let response = format!(
                        "HTTP/1.1 200 OK\r\nContent-Type: application/json\r\nAccess-Control-Allow-Origin: *\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
                        body.len(),
                        body
                    );
                    let _ = stream.write_all(response.as_bytes()).await;
                }
            }
        });

        let config = ServerConfig::builder()
            .with_bind_default(port)
            .with_identity(Identity::new(
                CertificateChain::single(Certificate::from_der((*cert_hash).clone()).unwrap_or_default()),
                PrivateKey::from_der_pkcs8(vec![]),
            ))
            .build();

        // Actually we need to regenerate identity from stored cert — let me restructure
        unreachable!()
    }

    pub async fn push_snapshot(&self, snapshot: Snapshot) {
        let _ = self.snapshot_tx.send(Some(snapshot));
    }
}

