                    room.state = RoomState::Ended;
                    ended.push((room.id.clone(), winner));
                }
            }
        }

        ended
    }

    /// Remove ended rooms that have no clients
    pub fn cleanup(&mut self) {
        self.rooms.retain(|_, r| {
            !(r.state == RoomState::Ended && r.all_client_ids().is_empty())
        });
    }
}

