const sendMovement = () => {
  const keys = keysRef.current;
  let dx = 0, dy = 0;
  if (keys.has('w')) dy += 1;
  if (keys.has('s')) dy -= 1;
  if (keys.has('a')) dx -= 1;
  if (keys.has('e')) dx += 1;

  if (dx === 0 && dy === 0) {
    clientRef.current?.send({ type: 'Command', command: { type: 'StopMove' } });
  } else {
    const len = Math.sqrt(dx * dx + dy * dy);
    clientRef.current?.send({ type: 'Command', command: { type: 'Move', dx: dx / len, dy: dy / len } });
  }
};

