use bevy_ecs::prelude::*;
use crate::room::Owner;

/// Resets player_controlled for all ships that aren't the human's selected ship.
/// Called at the start of each tick so bot commands must be re-sent each tick to maintain control.
pub fn reset_bot_control_system(
    mut ships: Query<(Entity, &mut Owner)>,
) {
    for (_, mut owner) in ships.iter_mut() {
        // Only reset if it was bot-controlled (not the human's selected ship)
        // We distinguish by: human-selected ships have auto_fire explicitly set
        // For simplicity: reset all player_controlled flags.
        // The human's selected ship will be re-marked by the SelectNextShip state.
        // Bot commands re-mark their ships each tick.
        owner.player_controlled = false;
    }
}

