                commands.push(WasmCommand::ShootFrom { ship_id, dx, dy });
            }
            2 => { // SetSpawnType
                if offset + 1 > data.len() { break; }
                let ship_type = data[offset];
                offset += 1;
                commands.push(WasmCommand::SetSpawnType { ship_type });
            }
            _ => break,
        }
    }

    commands
}

