pub fn create_room(&mut self, mode: GameMode, obstacles: bool) -> String {
    let id = generate_room_id();
    let mut room = Room::new(id.clone(), mode);
    room.obstacles_enabled = obstacles;
    if !obstacles {
        // Remove any spawned obstacles (Room::new spawns them by default)
        // Easiest: just recreate without obstacles
        room = Room::new_with_options(id.clone(), mode, obstacles);
    }
    self.rooms.insert(id.clone(), room);
    id
}

